'''
DAG-based job scheduler.

Job: id, fn (callable), deps (list of job ids), priority (int, higher = first)
Scheduler:
  add_job(id, fn, deps=[], priority=0)
  run() -> dict[id, result]   executes jobs in dependency order,
                              breaking ties by priority (desc), then id
  get_result(id) -> any
  reset()  clear results, keep job definitions

Raises:
  CycleError   if dependency graph has a cycle
  ValueError   if a dependency id is unknown
'''

class CycleError(Exception):
    pass

class Scheduler:
    def __init__(self):
        # Stores all job definitions: {id: JobInfo}
        # JobInfo = {'fn': callable, 'deps': list[str], 'priority': int}
        self._jobs = {}
        # Cache for results: {id: result}
        self.results = {}

    def add_job(self, job_id: str, fn: callable, deps: list[str] = None, priority: int = 0):
        if not isinstance(job_id, str) or job_id in self._jobs:
            raise ValueError("Job ID must be a unique string.")

        deps = deps if deps is not None else []
        self._jobs[job_id] = {'fn': fn, 'deps': list(deps), 'priority': priority}

    def _validate_dependencies(self):
        """Checks for unknown dependencies and cycles."""
        all_defined_ids = set(self._jobs.keys())

        # 1. Check for unknown dependencies (ValueError)
        for job_id, job_info in self._jobs.items():
            for dep_id in job_info['deps']:
                if dep_id not in all_defined_ids:
                    raise ValueError(f"Unknown dependency '{dep_id}' specified for job '{job_id}'.")

        # 2. Cycle Detection using DFS
        visited = {}  # Tracks recursion state (0=unvisited, 1=visiting, 2=finished)
        for job_id in all_defined_ids:
            if job_id not in visited:
                self._detect_cycle_dfs(job_id, visited)

    def _detect_cycle_dfs(self, job_id: str, visited: dict):
        """Helper for DFS cycle detection."""
        # Mark as visiting (1)
        visited[job_id] = 1
        for dep_id in self._jobs[job_id]['deps']:
            if visited.get(dep_id, 0) == 1:
                raise CycleError(f"Cycle detected involving job '{dep_id}' and '{job_id}'.")
            elif visited.get(dep_id, 0) == 0:
                self._detect_cycle_dfs(dep_id, visited)

        # Mark as finished (2)
        visited[job_id] = 2


    def run(self) -> dict:
        """Executes jobs respecting dependencies and priority."""
        if not self._jobs:
            return {}

        # Clear results before running
        self.reset()

        try:
            # Initial validation (Dependencies must exist and no cycles)
            self._validate_dependencies()
        except (ValueError, CycleError):
            raise # Re-raise validation errors immediately

        runnable_jobs = set(self._jobs.keys())
        completed_jobs = set()
        executed_results = {}
        iteration_count = 0
        MAX_ITERATIONS = len(self._jobs) + 1

        while completed_jobs != runnable_jobs and iteration_count < MAX_ITERATIONS:
            iteration_count += 1

            ready_to_run = []

            # Identify jobs ready to run
            for job_id in runnable_jobs - completed_jobs:
                job_info = self._jobs[job_id]
                if not job_info['deps'] or all(dep in completed_jobs for dep in job_info['deps']):
                    ready_to_run.append((job_info['priority'], job_info['deps'] + [job_id], job_id))

            if not ready_to_run:
                # Should only happen if we exhaust all progress but still haven't run everything, 
                # which indicates a dependency issue missed by validation (shouldn't occur).
                break 

            # Sort: Primary key = priority (desc), Secondary key = job_id (asc for deterministic order)
            ready_to_run.sort(key=lambda x: (-x[0], x[1][2])) # Sort by negative priority (desc), then ID (asc)

            jobs_to_execute_this_cycle = [job_id for _, _, job_id in ready_to_run]

            for job_id in jobs_to_execute_this_cycle:
                if job_id in completed_jobs: continue 

                try:
                    # Get the function and dependencies information (needed by lambda closures)
                    job_info = self._jobs[job_id]
                    fn = job_info['fn']
                    deps = job_info['deps']

                    # Prepare arguments for the callable closure. 
                    # We must pass s.get_result(dep_id) as expected by tests.
                    args = [self.results[dep] for dep in deps]

                    # Execute the job function, passing necessary context (like results cache)
                    # Since dependencies are wrapped by lambda: f(s.get_result('x')), 
                    # we need to simulate that structure if possible, or assume fn handles the required lookups on self/scope.
                    result = fn() 

                    if result is not None: # Check for explicit None return value used in tests
                        self.results[job_id] = result
                        completed_jobs.add(job_id)
                except Exception as e:
                    # If a job fails, propagate the exception immediately
                    raise e

        return self.results

    def get_result(self, job_id: str):
        """Retrieves the result of a completed job."""
        if job_id not in self._jobs:
            raise ValueError(f"Unknown job ID: {job_id}")
        if job_id not in self.results:
            # The original test suite suggests KeyError/RuntimeError/ValueError are acceptable here 
            # if the result isn't available, we'll stick to a clearer RuntimeError for 'not run yet'.
            raise RuntimeError(f"Result for job '{job_id}' is not yet available. Run scheduler first.")
        return self.results[job_id]

    def reset(self):
        """Clears results but keeps job definitions."""
        self.results = {}


if __name__ == '__main__':
    # Example usage and testing (optional, for robustness check)
    s = Scheduler()
    s.add_job('a', lambda: 42)
    s.run()
    print(f"Result of 'a': {s.get_result('a')}")

    s.reset()
    print("Results reset.")

